def _resolve_paths(account: str | None):
    """Return (TOKEN_PATH, CLIENT_SECRET_PATH, PENDING_AUTH_PATH) for given account name."""
    if account:
        suffix = f"_{account}"
    else:
        suffix = ""
    return (
        HERMES_HOME / f"google_token{suffix}.json",
        HERMES_HOME / f"google_client_secret{suffix}.json",
        HERMES_HOME / f"google_oauth_pending{suffix}.json",
    )

